/* SmsBackupMapper.deleteSmsBackupData */
DELETE FROM AM2X_SUBMIT_LOG
WHERE SCHEDULE_TIME <= TO_CHAR(ADD_MONTHS(TRUNC(SYSDATE), -6), 'YYYYMMDD') || '235959'

/* SmsBackupMapper.deleteSmsResend */
DELETE FROM MSP_SMS_RESEND_MST
WHERE SEND_REQ_DTTM <= TO_CHAR(ADD_MONTHS(TRUNC(SYSDATE), -6), 'YYYYMMDD') || '235959'
